import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def urgency_score(cscore, start_window, arrival_time):
        # Score lowers as the urgency to reach before the window closes increases
        if arrival_time < start_window:
            return cscore * (1 + 0.1 * (start_window - arrival_time)) 
        else:
            return cscore

    best_node = None
    minimum_score = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time

        start_window, end_window = time_windows[i]
        lateness_penalty = max(0, arrival_time - end_window) * 2
        earliness_penalty = max(0, start_window - arrival_time) * 0.5
        time_penalty = lateness_penalty + earliness_penalty

        # Initial score based solely on travel and time penalties
        base_score = travel_time + time_penalty

        # Adjust score by urgency to reach before the window starts
        urgency_adjusted_score = urgency_score(base_score, start_window, arrival_time)

        # Update best node based on minimum urgency adjusted score
        if urgency_adjusted_score < minimum_score:
            minimum_score = urgency_adjusted_score
            best_node = i

    return best_node
